// ========== n8n Code Node: Clean Gemini Output for Grok Refinement ==========

// Step 1: Extract raw text from Gemini response
const item = $input.first().json;  // Single item from Gemini
const rawText = item.content.parts[0].text;

// Step 2: Unwrap ```json fences
function unwrapJSON(text) {
  const match = text.match(/```json\s*([\s\S]*?)```/i);
  return match ? match[1].trim() : text.trim();
}

const cleanText = unwrapJSON(rawText);

// Step 3: Safe parse
function safeParse(str) {
  try {
    return JSON.parse(str);
  } catch (e) {
    console.error("Parse error:", e.message);
    return null;
  }
}

const parsed = safeParse(cleanText);
if (!parsed) {
  return [{ json: { error: "Failed to parse Gemini output", refined_errors: [] } }];
}

// Step 4: Extract key sections (readable for Grok)
const panel_map = parsed.panel_map || [];
const extracted_text = parsed.extracted_text || [];
const gemini_errors = parsed.errors_and_corrections || [];
const summary = parsed.summary || {};
const image_dimensions = parsed.image_dimensions || { width: 0, height: 0 };
const total_panels = parsed.total_panels_detected || 0;

// Step 5: Prepare "readable" data for Grok (stringified JSON + summary)
const grok_input = {
  original_gemini_errors: gemini_errors,  // Array for refinement
  extracted_text_summary: {
    total_items: extracted_text.length,
    panels_covered: total_panels,
    sample_texts: extracted_text.slice(0, 10).map(t => ({ panel_zone: t.panel_zone, text: t.text }))  // Sample for context (limit to avoid tokens)
  },
  image_dimensions: image_dimensions
};

// Stringify for prompt insertion (Grok sees clean JSON)
const grok_ready_json = JSON.stringify(grok_input, null, 2);

// Step 6: Output for next node (Grok call) – readable and structured
return [{
  json: {
    // Full parsed data (for logging/debug)
    full_parsed: parsed,

    // Readable for Grok prompt
    grok_input_json: grok_ready_json,

    // Quick stats
    total_gemini_errors: gemini_errors.length,
    total_extracted_texts: extracted_text.length,

    // Error preview (array for immediate use if no Grok)
    preliminary_errors: gemini_errors
  }
}];

// n8n Code Node – Extract Errors from Gemini/Grok/GPT Response
// Output: One clean item per error

const item = $input.all()[0]?.json || {};

// === 1. Extract raw text from ANY possible location ===
let raw = "";
if (typeof item === "string") {
  raw = item;
} else if (item.content) {
  raw = typeof item.content === "string" ? item.content : JSON.stringify(item.content);
} else if (item.choices?.[0]?.message?.content) {
  raw = item.choices[0].message.content;
} else if (item.content?.parts?.[0]?.text) {
  raw = item.content.parts[0].text;
} else if (item.candidates?.[0]?.content?.parts?.[0]?.text) {
  raw = item.candidates[0].content.parts[0].text;
} else {
  raw = JSON.stringify(item);
}

// === 2. Clean formatting - IMPROVED ===
raw = raw
  .replace(/```json|```/g, "")
  .replace(/\\n/g, "\n")           // Convert escaped \n to actual newlines
  .replace(/\\r/g, "")             // Remove \r
  .replace(/\\t/g, " ")            // Convert tabs to spaces
  .replace(/\\\"/g, '"')           // Unescape quotes
  .trim();

// === 3. Try to parse as complete JSON first ===
let parsedData = null;
try {
  parsedData = JSON.parse(raw);
} catch (e) {
  // If not valid JSON, continue with extraction
}

// === 4. Extract errors_and_corrections array ===
let errors = [];

if (parsedData && parsedData.errors_and_corrections) {
  errors = parsedData.errors_and_corrections;
} else if (Array.isArray(parsedData)) {
  errors = parsedData;
} else {
  // Fallback: Try to find the array in the string
  // More flexible regex that handles newlines and spaces
  const errorsArrayMatch = raw.match(/"errors_and_corrections"\s*:\s*\[([\s\S]*?)(?:\]|$)/i);

  if (!errorsArrayMatch) {
    return [{
      json: {
        error: "No errors_and_corrections found",
        raw_preview: raw.substring(0, 500),
        debug_raw: raw
      }
    }];
  }

  let errorsBlock = errorsArrayMatch[1].trim();

  // If empty array
  if (!errorsBlock || errorsBlock === "") {
    return [{
      json: {
        message: "No errors found in image",
        errors_count: 0
      }
    }];
  }

  // === 5. Split into individual error objects - IMPROVED ===
  // Handle incomplete JSON by finding all complete objects
  const objectMatches = [];
  let depth = 0;
  let currentObj = "";
  let inString = false;
  let escapeNext = false;

  for (let i = 0; i < errorsBlock.length; i++) {
    const char = errorsBlock[i];

    if (escapeNext) {
      currentObj += char;
      escapeNext = false;
      continue;
    }

    if (char === '\\') {
      escapeNext = true;
      currentObj += char;
      continue;
    }

    if (char === '"' && !escapeNext) {
      inString = !inString;
      currentObj += char;
      continue;
    }

    if (!inString) {
      if (char === '{') {
        if (depth === 0) currentObj = "";
        depth++;
        currentObj += char;
      } else if (char === '}') {
        depth--;
        currentObj += char;
        if (depth === 0 && currentObj.trim()) {
          objectMatches.push(currentObj.trim());
        }
      } else {
        currentObj += char;
      }
    } else {
      currentObj += char;
    }
  }

  // === 6. Parse each error object ===
  errors = objectMatches.map((str, index) => {
    try {
      // Clean common JSON issues
      let cleaned = str
        .replace(/,\s*}/g, "}")
        .replace(/,\s*]/g, "]")
        .replace(/:\s*,/g, ': "",')
        .replace(/:\s*undefined/g, ': null')
        .replace(/:\s*'([^']*)'/g, ': "$1"');

      return JSON.parse(cleaned);
    } catch (e) {
      // Fallback: extract with regex if JSON parsing fails
      return {
        error_id: index + 1,
        found_text: (str.match(/"found_text"\s*:\s*"([^"]*)"/i)?.[1] || "Unknown").trim(),
        corrected_text: str.match(/"corrected_text"\s*:\s*"([^"]*)"/i)?.[1] || null,
        error_type: str.match(/"error_type"\s*:\s*"([^"]*)"/i)?.[1] || "Unknown",
        issue_description: str.match(/"issue_description"\s*:\s*"([^"]*)"/i)?.[1] || "Parsing failed",
        panel_zone: str.match(/"panel_zone"\s*:\s*"([^"]*)"/i)?.[1] || null,
        coordinates: null,
        parse_warning: "Fallback regex extraction used"
      };
    }
  });
}

// === 7. Return empty result if no errors ===
if (!errors || errors.length === 0) {
  return [{
    json: {
      message: "No errors found in image",
      errors_count: 0
    }
  }];
}

// === 8. Normalize and return one item per error ===
return errors.map((error, index) => ({
  json: {
    error_id: error.error_id ?? index + 1,
    found_text: (error.found_text || "").trim(),
    corrected_text: error.corrected_text || null,
    error_type: error.error_type || "Unknown",
    issue_description: error.issue_description || error.issue || "No description",
    panel_zone: error.panel_zone || null,
    coordinates: error.coordinates || null,
    confidence: error.confidence || null
  },
  pairedItem: { item: 0 }
}));

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
let dimensions =$input.first().json.full_parsed.image_metadata

return dimensions;
